void backtrack(/* state */)
{
    // base case: record a complete result

    for (/* each possible choice */)
    {
        // CHOOSE — make the choice
        backtrack(/* updated state */); // EXPLORE — recurse deeper
        // UNCHOOSE — undo the choice before trying the next one
    }
}

#include <iostream>
#include <vector>

using namespace std;

void backtrack(vector<int> &numbers, int index, vector<int> &current)
{
    if (index == numbers.size()) // BASE CASE — decision made for every element
    {
        for (int n : current)
        {
            cout << n << " ";
        }
        cout << "| ";
        return;
    }

    // CHOICE 1: exclude numbers[index]
    backtrack(numbers, index + 1, current);

    // CHOICE 2: include numbers[index]
    current.push_back(numbers[index]); // CHOOSE
    backtrack(numbers, index + 1, current); // EXPLORE
    current.pop_back(); // UNCHOOSE — undo before returning
}

int main()
{
    vector<int> numbers = {1, 2, 3};
    vector<int> current;

    backtrack(numbers, 0, current);

    return 0;
}

