#include <iostream>
#include <vector>

using namespace std;

vector<vector<int>> subsets(vector<int> &nums)
{
    int n = nums.size();
    vector<vector<int>> result;

    for (int mask = 0; mask < (1 << n); mask++)
    {
        vector<int> subset;
        for (int i = 0; i < n; i++)
        {
            if (mask & (1 << i)) subset.push_back(nums[i]);
        }
        result.push_back(subset);
    }

    return result;
}

int main()
{
    vector<int> nums = {1, 2, 3};

    auto result = subsets(nums);
    cout << result.size() << endl;

    return 0;
}

#include <iostream>
#include <vector>

using namespace std;

void backtrack(vector<int> &nums, int index, vector<int> &current, vector<vector<int>> &result)
{
    if (index == nums.size())
    {
        result.push_back(current);
        return;
    }

    backtrack(nums, index + 1, current, result); // exclude

    current.push_back(nums[index]);
    backtrack(nums, index + 1, current, result); // include
    current.pop_back();
}

vector<vector<int>> subsets(vector<int> &nums)
{
    vector<vector<int>> result;
    vector<int> current;
    backtrack(nums, 0, current, result);
    return result;
}

int main()
{
    vector<int> nums = {1, 2, 3};

    auto result = subsets(nums);
    cout << result.size() << endl;

    return 0;
}

